parameters.content:
/**
 * Notification service — dispatches notifications via the EventBus pattern.
 *
 * Architecture: When domain events occur (e.g. order:created), this service
 * translates them into notification:send events on the EventBus. Channel
 * handlers (email, SMS, etc.) subscribe to notification:send and deliver
 * through their respective transports.
 *
 * This design decouples notification triggering from delivery — new channels
 * can be added by implementing NotificationChannel and registering with
 * the service, without modifying existing code.
 *
 * Depends on:
 * - EventBus (event system) for publishing and subscribing to events
 * - CallbackRegistry (direct callbacks) for order:status-changed events
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  NotificationSendEvent,
} from '../events/event-types.js';
import { statusChangeCallbacks } from '../utils/callback-registry.js';
import { Logger } from '../utils/logger.js';

export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  sentAt: Date;
}

/**
 * Interface for notification delivery channels.
 * Implement this to add new delivery mechanisms (email, SMS, push, etc.).
 */
export interface NotificationChannel {
  /** Unique name identifying this channel. */
  readonly name: string;
  /** Deliver a notification through this channel. */
  send(notification: Notification): void | Promise<void>;
}

/**
 * Email notification channel — delivers notifications via email.
 *
 * In this implementation, sent emails are stored in-memory for
 * inspection and testing. A production implementation would use
 * an SMTP client or email API.
 */
export class EmailNotificationChannel implements NotificationChannel {
  readonly name = 'email';
  private logger = new Logger('EmailChannel');
  private sentEmails: Notification[] = [];

  /** Deliver a notification as an email. */
  send(notification: Notification): void {
    this.logger.info(
      `Sending email to ${notification.recipient}: ${notification.subject}`,
    );
    this.sentEmails.push({ ...notification });
  }

  /** Get all sent emails. */
  getSentEmails(): Notification[] {
    return [...this.sentEmails];
  }

  /** Clear sent emails (useful for testing). */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private channels: NotificationChannel[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register a notification channel. The channel will subscribe to
   * notification:send events on the EventBus and deliver each notification.
   */
  addChannel(channel: NotificationChannel): void {
    this.channels.push(channel);
    this.eventBus.on<NotificationSendEvent>('notification:send', (event) => {
      const notification: Notification = {
        id: generateNotificationId(),
        recipient: event.recipient,
        subject: event.subject,
        body: event.body,
        sentAt: event.timestamp,
      };
      this.notifications.push(notification);
      channel.send(notification);
      this.logger.info(
        `Notification ${notification.id} delivered via ${channel.name} to ${notification.recipient}`,
      );
    });
  }

  /**
   * Register event handlers for notification triggers.
   *
   * Uses EventBus for order creation (event-driven pattern)
   * and CallbackRegistry for status changes (direct callback pattern).
   */
  private registerHandlers(): void {
    // Pattern 1: EventBus subscription for order creation
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    // Pattern 2: CallbackRegistry for status changes
    statusChangeCallbacks.register((event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — publish notification:send event.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.publishNotification({
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
    });
  }

  /**
   * Handle order status change — publish notification:send event.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.publishNotification({
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
    });
  }

  /**
   * Publish a notification:send event on the EventBus.
   * If no channels are registered, stores the notification directly
   * for backward compatibility.
   */
  private publishNotification(params: {
    recipient: string;
    subject: string;
    body: string;
  }): void {
    if (this.channels.length > 0) {
      this.eventBus.emit({
        type: 'notification:send' as const,
        recipient: params.recipient,
        subject: params.subject,
        body: params.body,
        timestamp: new Date(),
      });
    } else {
      // Backward-compatible: store directly when no channels registered
      const notification: Notification = {
        id: generateNotificationId(),
        recipient: params.recipient,
        subject: params.subject,
        body: params.body,
        sentAt: new Date(),
      };
      this.notifications.push(notification);
      this.logger.info(`Notification sent: ${notification.id} to ${params.recipient}`);
    }
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

